### Handle Errors and Stream Responses with Claude Agent SDK (TypeScript)

Source: https://context7.com/anthropics/claude-agent-sdk-typescript/llms.txt

This snippet demonstrates how to query the Claude Agent SDK, process its streaming responses by switching on various message types (assistant, tool_call, tool_result, error, system), and implement comprehensive error handling for both streaming messages and top-level query failures, including specific error codes like authentication or rate limit issues.

```typescript
import { query } from "@anthropic-ai/claude-agent-sdk";

async function processWithErrorHandling() {
  try {
    const response = query({
      prompt: "Analyze and refactor the payment processing module",
      options: {
        model: "claude-sonnet-4-5",
        workingDirectory: "/path/to/project",
        permissionMode: "default"
      }
    });

    for await (const message of response) {
      switch (message.type) {
        case 'assistant':
          // Handle assistant messages
          if (typeof message.content === 'string') {
            console.log('Assistant:', message.content);
          } else {
            message.content.forEach(block => {
              if (block.type === 'text') {
                console.log('Text:', block.text);
              } else if (block.type === 'tool_use') {
                console.log(`Tool request: ${block.name}`);
              }
            });
          }
          break;

        case 'tool_call':
          console.log(`Executing tool: ${message.tool_name}`);
          console.log(`Input:`, JSON.stringify(message.input, null, 2));
          break;

        case 'tool_result':
          console.log(`Tool ${message.tool_name} result:`, message.result);
          break;

        case 'error':
          console.error('Agent error:', message.error);
          if (message.error.type === 'permission_denied') {
            console.log('Permission was denied for:', message.error.tool);
          }
          break;

        case 'system':
          if (message.subtype === 'init') {
            console.log(`Session ID: ${message.session_id}`);
          } else if (message.subtype === 'completion') {
            console.log('Task completed');
          }
          break;

        default:
          console.log('Other message:', message);
      }
    }
  } catch (error) {
    console.error('Fatal error:', error);

    // Handle specific error types
    if (error.code === 'AUTHENTICATION_FAILED') {
      console.error('Check your API key configuration');
    } else if (error.code === 'RATE_LIMIT_EXCEEDED') {
      console.error('Rate limit exceeded, retry after delay');
    } else if (error.code === 'CONTEXT_LENGTH_EXCEEDED') {
      console.error('Context too large, consider session compaction');
    }
  }
}

processWithErrorHandling();
```

