### Handle Agent Response Stream with Message Type Routing

Source: https://context7.com/anthropics/claude-agent-sdk-typescript/llms.txt

Process async messages from the agent response stream by routing different message types (system, assistant, tool_call, error) to appropriate handlers. Captures session ID, collects results, and implements error handling for robust agent execution.

```typescript
let sessionId: string | undefined;
const results: string[] = [];

try {
  for await (const message of response) {
    switch (message.type) {
      case 'system':
        if (message.subtype === 'init') {
          sessionId = message.session_id;
          console.log(`Session started: ${sessionId}`);
        }
        break;

      case 'assistant':
        results.push(message.content);
        console.log('Agent:', message.content);
        break;

      case 'tool_call':
        console.log(`Executing: ${message.tool_name}`);
        break;

      case 'error':
        console.error('Error:', message.error);
        break;
    }
  }
} catch (error) {
  console.error('Agent failed:', error);
  throw error;
}

return { sessionId, results };
```

